sql:
SELECT experiment_id
FROM experiments
ORDER BY date_started ASC, experiment_name ASC;

external_knowledge:
- Successful experiments refer to those with a status of 'completed';
- Perplexity value and explained variance are metrics used to evaluate the performance of experiments;
- A higher perplexity value indicates lower performance, and a higher explained variance indicates better performance.

sql:
SELECT experiment_id, average_policy_std
FROM average_policy_std
WHERE experiment_id = 1;

SELECT AVG(entropy_value) AS average_entropy
FROM entropy_metrics
WHERE experiment_id = 0;

SELECT AVG(trajectory_length) AS avg_trajectory_length
FROM trajectories
WHERE experiment_id = 0;

SELECT variance_name, AVG(explained_variance) AS average_variance
FROM explained_variance
GROUP BY variance_name;

SELECT entropy_value
FROM entropy_metrics
WHERE experiment_id = 0;

SELECT entropy_name, AVG(entropy_value) AS average_entropy
FROM entropy_metrics
GROUP BY entropy_name;
